module comparator_64bit(  
    input [63:0] A,  
    input [63:0] B,  
    output reg [2:0] status  
);  
    always @* begin  
        if (A < B)  
            status = 3'b001;  
        else if (A == B)  
            status = 3'b010;  
        else  
            status = 3'b100;  
    end  
endmodule
